-- Program: Beach Body Ready
-- Category: Hypertrophy/Muscle Building -> hypertrophy
-- Priority: Medium
-- Durations: [4, 8, 12], Sessions: [5]

-- Insert branded program
INSERT INTO branded_programs (
    name, description, category, difficulty_level,
    duration_weeks, sessions_per_week, split_type,
    goals, requires_gym, is_active
) VALUES (
    'Beach Body Ready',
    'A 12-week aesthetic hypertrophy program designed to build a lean, muscular beach physique. 5-day split targeting chest/back, shoulders/arms, legs, upper body, and glute/ham emphasis. Includes strategic deload weeks and phases from foundation building to metabolic shredding.',
    'hypertrophy',
    'beginner',
    12,
    5,
    'circuit',
    ARRAY['Maximize muscle hypertrophy', 'Time under tension', 'Maximize calorie burn', 'Preserve lean muscle', 'Promote active recovery']::text[],
    true,
    true
) ON CONFLICT (name) DO UPDATE SET
    description = EXCLUDED.description,
    category = EXCLUDED.category,
    difficulty_level = EXCLUDED.difficulty_level,
    duration_weeks = EXCLUDED.duration_weeks,
    sessions_per_week = EXCLUDED.sessions_per_week,
    split_type = EXCLUDED.split_type,
    goals = EXCLUDED.goals,
    requires_gym = EXCLUDED.requires_gym,
    updated_at = NOW();

-- Variant: Beach Body Ready - 4w 5x/wk
INSERT INTO program_variants (
    base_program_id,
    intensity_level,
    duration_weeks,
    variant_name,
    program_category,
    sessions_per_week,
    session_duration_minutes,
    goals,
    workouts
) SELECT
    bp.id,
    'Medium',
    4,
    'Beach Body Ready - 4w 5x/wk',
    'hypertrophy',
    5,
    60,
    ARRAY['Maximize muscle hypertrophy', 'Time under tension', 'Maximize calorie burn', 'Preserve lean muscle', 'Promote active recovery']::text[],
    '[]'::jsonb
FROM branded_programs bp
WHERE bp.name = 'Beach Body Ready'
ON CONFLICT DO NOTHING;

