    'Beach Body Ready',
    'Beach Body Ready - 4w 5x/wk',
    'Medium',
    false,
    'A 12-week aesthetic hypertrophy program designed to build a lean, muscular beach physique. 5-day split targeting chest/back, shoulders/arms, legs, upper body, and glute/ham emphasis. Includes strategic deload weeks and phases from foundation building to metabolic shredding.',
    'Hypertrophy/Muscle Building'
FROM program_variants pv
JOIN branded_programs bp ON bp.id = pv.base_program_id
WHERE bp.name = 'Beach Body Ready'
  AND pv.duration_weeks = 4
  AND pv.sessions_per_week = 5
ON CONFLICT DO NOTHING;

